const root = items[0].json;
const body = root.body !== undefined ? root.body : root;
const esc = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\"/g, '&quot;');

const payload = {
  submissionId: body.submissionId ?? '',
  company: body.company ?? 'Kjells Konserverade Koi',
  name: body.name ?? '',
  email: body.email ?? '',
  phone: body.phone ?? '',
  product: body.product ?? '',
  quantity: body.quantity ?? '',
  city: body.city ?? '',
  category: body.category ?? 'legacy_case',
  issue: body.issue ?? '',
  source: body.source ?? 'n8n-webhook',
  profileUrl: body.profileUrl ?? '',
  rawBlob: body.rawBlob ?? body.blob ?? '',
};

const rows = [
  ['Submission ID', payload.submissionId],
  ['Företag', payload.company],
  ['Namn', payload.name],
  ['E-post', payload.email],
  ['Telefon', payload.phone],
  ['Produkt', payload.product],
  ['Antal', payload.quantity],
  ['Stad', payload.city],
  ['Kategori', payload.category],
  ['Källa', payload.source],
  ['Kommentar', payload.issue],
].filter(([, value]) => value);

const tableRows = rows.map(([label, value]) => `<tr><th>${esc(label)}</th><td>${esc(value)}</td></tr>`).join('');
const rawBlobBlock = payload.rawBlob
  ? `<details><summary>Visa ursprunglig blob</summary><pre>${esc(payload.rawBlob)}</pre></details>`
  : '';
const previewCard = payload.profileUrl
  ? `<section class=\"preview\"><img src=\"${esc(payload.profileUrl)}\" alt=\"Reward preview\" /><div><h2>Regex reward unlocked</h2><p>Blobben är nu uppstrukturerad. Eleven får direkt en visuell belöning när \`profileUrl\` lyckats extraheras korrekt.</p><p class=\"tiny\">Tips: byt bild-URL eller avatar-generator om ni vill göra olika teman per case.</p></div></section>`
  : `<section class=\"preview preview-empty\"><div><h2>Ingen bild vald</h2><p>Skicka med <code>profileUrl</code> för att låsa upp reward-bilden.</p></div></section>`;

items[0].json = {
  ...payload,
  html: `<!doctype html>
<html lang=\"sv\">
  <head>
    <meta charset=\"utf-8\" />
    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />
    <title>Legacy reward preview</title>
    <style>
      :root {
        --bg: #08111d;
        --panel: #14253c;
        --card: #19324f;
        --text: #edf7ff;
        --muted: #a9c3d8;
        --accent: #7ce6ca;
        --accent2: #ffc777;
      }
      * { box-sizing: border-box; }
      body {
        margin: 0;
        font-family: \"Segoe UI\", sans-serif;
        color: var(--text);
        background:
          radial-gradient(1000px 520px at 10% 0%, rgba(124, 230, 202, 0.16), transparent 48%),
          radial-gradient(860px 420px at 92% 10%, rgba(255, 199, 119, 0.15), transparent 44%),
          linear-gradient(180deg, #08111d, #0d1827);
      }
      main {
        max-width: 980px;
        margin: 0 auto;
        padding: 2rem 1.15rem 3rem;
      }
      .hero, .panel {
        border-radius: 20px;
        padding: 1rem 1.1rem 1.2rem;
        background: linear-gradient(180deg, rgba(25, 50, 79, 0.96), rgba(20, 37, 60, 0.96));
        border: 1px solid rgba(255, 255, 255, 0.08);
      }
      .hero h1 { margin: 0 0 0.35rem; font-size: clamp(1.8rem, 3vw, 2.5rem); }
      .hero p, .tiny { color: var(--muted); }
      .pill {
        display: inline-block;
        margin-bottom: 0.7rem;
        padding: 0.28rem 0.62rem;
        border-radius: 999px;
        background: rgba(124, 230, 202, 0.12);
        color: var(--accent);
        font-size: 0.82rem;
        letter-spacing: 0.05em;
        text-transform: uppercase;
      }
      .grid {
        display: grid;
        grid-template-columns: 1.1fr 0.9fr;
        gap: 1rem;
        margin-top: 1rem;
      }
      table {
        width: 100%;
        border-collapse: collapse;
      }
      th, td {
        padding: 0.65rem 0.72rem;
        border-bottom: 1px solid rgba(255, 255, 255, 0.08);
        text-align: left;
        vertical-align: top;
      }
      th { width: 32%; color: var(--accent2); font-weight: 700; }
      .preview {
        display: grid;
        gap: 0.95rem;
        align-items: start;
      }
      .preview img {
        width: 100%;
        max-width: 280px;
        aspect-ratio: 1 / 1;
        object-fit: cover;
        border-radius: 18px;
        border: 1px solid rgba(255, 255, 255, 0.1);
        background: rgba(255, 255, 255, 0.04);
      }
      .preview-empty {
        min-height: 240px;
        place-items: center;
      }
      details { margin-top: 1rem; }
      pre {
        overflow: auto;
        white-space: pre-wrap;
        padding: 0.8rem;
        border-radius: 12px;
        background: rgba(0, 0, 0, 0.28);
        border: 1px solid rgba(255, 255, 255, 0.08);
      }
      code {
        font-family: ui-monospace, monospace;
        background: rgba(255, 255, 255, 0.06);
        border-radius: 6px;
        padding: 0.1rem 0.3rem;
      }
      @media (max-width: 860px) {
        .grid { grid-template-columns: 1fr; }
      }
    </style>
  </head>
  <body>
    <main>
      <section class=\"hero\">
        <span class=\"pill\">Webhook reward</span>
        <h1>Legacy-datan är nu begriplig</h1>
        <p>Det här är sista steget i övningen: regex-parsad blob in, tydlig preview ut. Samma princip fungerar för CRM, sheets eller andra integrationsmål.</p>
      </section>
      <section class=\"grid\">
        <article class=\"panel\">
          <h2>Strukturerad data</h2>
          <table>${tableRows || '<tr><td colspan=\"2\">Ingen data skickades in.</td></tr>'}</table>
          ${rawBlobBlock}
        </article>
        <aside class=\"panel\">
          ${previewCard}
        </aside>
      </section>
    </main>
  </body>
</html>`
};
return items;
